    36→static void dump_bl_cmd(freenect_context* ctx, bootloader_command cmd) {
    37→	int i;
    38→	for(i = 0; i < 24; i++)
    39→		FN_INFO("%02X ", ((unsigned char*)(&cmd))[i]);
    40→	FN_INFO("\n");
    41→}
    42→
    43→static void dump_cemd_cmd(freenect_context* ctx, cemdloader_command cmd) {
    44→	int i;
    45→	for(i = 0; i < 24; i++)
    46→		FN_INFO("%02X ", ((unsigned char*)(&cmd))[i]);
    47→	FN_INFO("(%d more zeros)\n", (int)(sizeof(cmd)-24));
    48→}
