   234→FN_INTERNAL int upload_firmware_from_memory(fnusb_dev* dev, unsigned char * fw_from_mem, unsigned int fw_size_in_btyes) {
   235→    freenect_context* ctx = dev->parent->parent;
   236→	bootloader_command bootcmd;
   237→	memset(&bootcmd, 0, sizeof(bootcmd));
   238→	bootcmd.magic = fn_le32(0x06022009);
   239→
   240→	int res;
   241→	int transferred;
   242→    
   243→	firmware_header fwheader;
   244→	int read = 0;
   245→    int bytesLeft = fw_size_in_btyes;
   246→    unsigned char * readPtr = &fw_from_mem[0];
   247→    
   248→	if (fw_size_in_btyes < sizeof(firmware_header)) {
   249→		FN_ERROR("upload_firmware: firmware image too small, has no header?\n");
   250→		return -errno;
   251→	}
   252→    
   253→    memcpy(&fwheader, readPtr, sizeof(firmware_header));
   254→
   255→	// The file is serialized as little endian.
   256→	fwheader.magic = fn_le32(fwheader.magic);
   257→	fwheader.ver_major = fn_le16(fwheader.ver_major);
   258→	fwheader.ver_minor = fn_le16(fwheader.ver_minor);
   259→	fwheader.ver_release = fn_le16(fwheader.ver_release);
   260→	fwheader.ver_patch = fn_le16(fwheader.ver_patch);
   261→	fwheader.base_addr = fn_le32(fwheader.base_addr);
   262→	fwheader.size = fn_le32(fwheader.size);
   263→	fwheader.entry_addr = fn_le32(fwheader.entry_addr);
   264→	FN_INFO("Found firmware image:\n");
   265→	FN_INFO("\tmagic        %08X\n", fwheader.magic);
   266→	FN_INFO("\tversion      %02d.%02d.%02d.%02d\n", fwheader.ver_major, fwheader.ver_minor, fwheader.ver_release, fwheader.ver_patch);
   267→	FN_INFO("\tbase address 0x%08x\n", fwheader.base_addr);
   268→	FN_INFO("\tsize         0x%08x\n", fwheader.size);
   269→	FN_INFO("\tentry point  0x%08x\n", fwheader.entry_addr);
   270→
   271→    
   272→    uint32_t addr = fwheader.base_addr;
   273→	unsigned char page[0x4000];
   274→    int readIndex = 0;
   275→	int total_bytes_sent = 0;
   276→	do {
   277→
   278→		read = (0x4000 > fwheader.size - total_bytes_sent) ? fwheader.size - total_bytes_sent : 0x4000;
   279→        
   280→        // sanity check
   281→        if( read > bytesLeft ){
   282→            read = bytesLeft;
   283→        }
   284→        if (read <= 0) {
   285→            break;
   286→        }
   287→        
   288→        memcpy(page, &readPtr[readIndex], read);
   289→        readIndex += read;
   290→        bytesLeft -= read;
   291→        
   292→		bootcmd.tag = fn_le32(dev->parent->audio_tag);
   293→		bootcmd.bytes = fn_le32(read);
   294→		bootcmd.cmd = fn_le32(0x03);
   295→		bootcmd.addr = fn_le32(addr);
   296→		FN_INFO("About to send: ");
   297→		dump_bl_cmd(ctx, bootcmd);
   298→		// Send it off!
   299→		res = fnusb_bulk(dev, 1, (unsigned char*)&bootcmd, sizeof(bootcmd), &transferred);
   300→		if(res != 0 || transferred != sizeof(bootcmd)) {
   301→			FN_ERROR("upload_firmware(): Error: res: %d\ttransferred: %d (expected %d)\n",res, transferred, (int)(sizeof(bootcmd)));
   302→			return -1;
   303→		}
   304→		int bytes_sent = 0;
   305→		while(bytes_sent < read) {
   306→			int to_send = (read - bytes_sent > 512 ? 512 : read - bytes_sent);
   307→			res = fnusb_bulk(dev, 1, &page[bytes_sent], to_send, &transferred);
   308→			if(res != 0 || transferred != to_send) {
   309→				FN_ERROR("upload_firmware(): Error: res: %d\ttransferred: %d (expected %d)\n",res, transferred, to_send);
   310→				return -1;
   311→			}
   312→			bytes_sent += to_send;
   313→			total_bytes_sent += to_send;
   314→		}
   315→		res = get_reply(dev);
   316→		addr += (uint32_t)read;
   317→		dev->parent->audio_tag++;
   318→	} while (read > 0);
   319→
   320→	if (total_bytes_sent != fwheader.size) {
   321→		FN_ERROR("upload_firmware: firmware image declared %d bytes, but file only contained %d bytes\n", fwheader.size, total_bytes_sent);
   322→		return -1;
   323→	}
   324→
   325→	bootcmd.tag   = fn_le32(dev->parent->audio_tag);
   326→	bootcmd.bytes = fn_le32(0);
   327→	bootcmd.cmd   = fn_le32(0x04);
   328→	bootcmd.addr  = fn_le32(fwheader.entry_addr);
   329→	dump_bl_cmd(ctx, bootcmd);
   330→	res = fnusb_bulk(dev, 1, (unsigned char*)&bootcmd, sizeof(bootcmd), &transferred);
   331→	if(res != 0 || transferred != sizeof(bootcmd)) {
   332→		FN_ERROR("upload_firmware(): Error: res: %d\ttransferred: %d (expected %d)\n", res, transferred, (int)sizeof(bootcmd));
   333→		return -1;
   334→	}
   335→	res = get_reply(dev);
   336→	dev->parent->audio_tag++;
   337→	FN_INFO("Firmware successfully uploaded and launched.  Device will disconnect and reenumerate.\n");
   338→	return 0;
   339→}
   340→
   341→FN_INTERNAL int upload_cemd_data(fnusb_dev* dev) {
   342→	// Now we upload the CEMD data.
   343→	freenect_context* ctx = dev->parent->parent;
   344→	cemdloader_command cemdcmd;
   345→	memset(&cemdcmd, 0, sizeof(cemdcmd));
   346→	cemdcmd.magic = fn_le32(0x06022009);
   347→	cemdcmd.tag   = fn_le32(dev->parent->audio_tag);
   348→	cemdcmd.arg1  = fn_le32(0);
   349→	cemdcmd.cmd   = fn_le32(0x00000133);
   350→	cemdcmd.arg2  = fn_le32(0x00064014); // This is the length of the CEMD data.
   351→	FN_INFO("Starting CEMD data upload:\n");
   352→	int res;
   353→	int transferred;
   354→	res = fnusb_bulk(dev, 1, (unsigned char*)&cemdcmd, sizeof(cemdcmd), &transferred);
   355→	if(res != 0 || transferred != sizeof(cemdcmd)) {
   356→		FN_ERROR("Error: res: %d\ttransferred: %d (expected %d)\n", res, transferred, (int)sizeof(cemdcmd));
   357→		return -1;
   358→	}
   359→	res = get_reply(dev);
   360→	dev->parent->audio_tag++;
   361→
   362→	const char* cemd_filename = "cemd_data.bin";
   363→	FILE* cf = fopen(cemd_filename, "r");
   364→	if(cf == NULL) {
   365→		FN_ERROR("upload_cemd_data: Failed to open %s: error %d", cemd_filename, errno);
   366→		return errno;
   367→	}
   368→	uint32_t addr = 0x00000000;
   369→	int read = 0;
   370→	unsigned char page[0x4000];
   371→	do {
   372→		read = fread(page, 1, 0x4000, cf);
   373→		if(read <= 0) {
   374→			break;
   375→		}
   376→		//LOG("");
   377→		cemdcmd.tag  = fn_le32(dev->parent->audio_tag);
   378→		cemdcmd.arg1 = fn_le32(read);
   379→		cemdcmd.cmd  = fn_le32(0x134);
   380→		cemdcmd.arg2 = fn_le32(addr);
   381→		FN_INFO("About to send: ");
   382→		dump_cemd_cmd(ctx, cemdcmd);
   383→		// Send it off!
   384→		res = fnusb_bulk(dev, 1, (unsigned char*)&cemdcmd, sizeof(cemdcmd), &transferred);
   385→		if(res != 0 || transferred != sizeof(cemdcmd)) {
   386→			FN_ERROR("Error: res: %d\ttransferred: %d (expected %d)\n",res, transferred, (int)sizeof(cemdcmd));
   387→			return -1;
   388→		}
   389→		int bytes_sent = 0;
   390→		while(bytes_sent < read) {
   391→			int to_send = (read - bytes_sent > 512 ? 512 : read - bytes_sent);
   392→			res = fnusb_bulk(dev, 1, &page[bytes_sent], to_send, &transferred);
   393→			if(res != 0 || transferred != to_send) {
   394→				FN_ERROR("Error: res: %d\ttransferred: %d (expected %d)\n",res, transferred, to_send);
   395→				return -1;
   396→			}
   397→			bytes_sent += to_send;
   398→		}
   399→		res = get_reply(dev);
   400→		addr += (uint32_t)read;
   401→		dev->parent->audio_tag++;
   402→	} while (read > 0);
   403→	fclose(cf);
   404→	cf = NULL;
   405→
   406→	cemdcmd.tag  = fn_le32(dev->parent->audio_tag);
   407→	cemdcmd.arg1 = fn_le32(0); // bytes = 0
   408→	cemdcmd.cmd  = fn_le32(0x135);
   409→	cemdcmd.arg2 = fn_le32(0x00064000); // mimicing the USB logs.  This is the # of bytes of actual CEMD data after the 20-byte CEMD header.
   410→	FN_INFO("Finishing CEMD data upload...\n");
   411→	res = fnusb_bulk(dev, 1, (unsigned char*)&cemdcmd, sizeof(cemdcmd), &transferred);
   412→	if(res != 0 || transferred != sizeof(cemdcmd)) {
   413→		FN_ERROR("upload_cemd_data(): Error: res: %d\ttransferred: %d (expected %d)\n", res, transferred, (int)sizeof(cemdcmd));
   414→		return -1;
   415→	}
   416→	res = get_reply(dev);
   417→	dev->parent->audio_tag++;
   418→	FN_INFO("CEMD data uploaded successfully.\n");
   419→	return 0;
   420→}
